      widthMm: Number(builtin.parameters.widthMm ?? 1200),
      riserMm: Number(builtin.parameters.riserMm ?? 175),
      treadMm: Number(builtin.parameters.treadMm ?? 280),
      overrideParams: { familyTypeId: builtin.id },
