        paramValues: {},
      },
      {
        'thumbnail-level': {
          kind: 'level',
          id: 'thumbnail-level',
          name: 'Preview',
          elevationMm: 0,
        },
        [entry.id]: {
          kind: 'asset_library_entry',
          id: entry.id,
