    entry?.thumbnailHeightMm ??
    defaults.depthMm;
  const heightMm = numericParam(entry, asset, ['heightMm', 'seatHeightMm']) ?? defaults.heightMm;

  return {
    symbolKind,
    widthM: THREE.MathUtils.clamp(widthMm / 1000, 0.05, 20),
