function addCircle(
  group: THREE.Group,
  cx: number,
  cz: number,
  radius: number,
  mat: THREE.LineBasicMaterial,
  pickId: string,
  segments = 28,
): void {
  const pts: Array<[number, number]> = [];
  for (let i = 0; i <= segments; i += 1) {
    const a = (i / segments) * Math.PI * 2;
    pts.push([cx + Math.cos(a) * radius, cz + Math.sin(a) * radius]);
