    renderer = new THREE.WebGLRenderer({ canvas, antialias: true, alpha: true });
    renderer.setSize(SIZE, SIZE, false);
    renderer.setClearColor(0xf3f4f6, 1);
    return renderer;
  } catch {
    renderer = null;
    return null;
