    layers: input.layers.map((layer) => ({
      thicknessMm: layer.thicknessMm,
      materialKey: layer.materialKey ?? '',
      function: normalizeCoreLayerFunction(layer.function),
    })),
  };
  const floor: Extract<Element, { kind: 'floor' }> = {
